// W-8 Signal Classifier -- Shadow Mode
// Categoriza sinais de W-1/W-5/W-3 antes de qualquer notificacao
// Shadow Mode: classifica mas NAO bloqueia sinais existentes
// P-110: fallback = W-1/W-5/W-3 passam direto se W-8 offline

const payload = $input.first().json;

// Schema do sinal recebido
const sinal = {
  origem: payload.origem || 'DESCONHECIDO',  // W-1 | W-3 | W-5
  cliente: payload.cliente || '',
  tipo: payload.tipo || '',
  dados: payload.dados || {},
  timestamp: payload.timestamp || new Date().toISOString()
};

// Regras de classificacao (calibrar apos 7 dias shadow mode)
let categoria = 'INFORMAR';
let grau = null;
let motivo = '';
let silenciar = false;

// --- AUTO-RESOLVE: sinais que nao precisam de atencao imediata ---
if (
  // Check-in de rotina sem anomalia
  (sinal.origem === 'W-1' && sinal.tipo === 'check_in' && sinal.dados.status === 'OK') ||
  // GitHub push em branch nao-master
  (sinal.origem === 'W-3' && sinal.tipo === 'push' && sinal.dados.branch && sinal.dados.branch !== 'master') ||
  // ChurnWatch sem alerta
  (sinal.origem === 'W-5' && sinal.tipo === 'check_rotina') ||
  // Supabase OK (W-2)
  (sinal.origem === 'W-2' && sinal.tipo === 'health_check' && sinal.dados.status === 'UP')
) {
  categoria = 'AUTO-RESOLVE';
  motivo = 'Sinal de rotina sem anomalia detectada';
  silenciar = true;
}

// --- DELIBERAR-A: requer Eduardo antes de qualquer acao ---
else if (
  // Churn critico (>2x threshold)
  (sinal.origem === 'W-5' && sinal.tipo === 'churn_critico') ||
  // Push para master com mudancas em arquivos criticos
  (sinal.origem === 'W-3' && sinal.tipo === 'push' && sinal.dados.branch === 'master' &&
    sinal.dados.arquivos_criticos && sinal.dados.arquivos_criticos.length > 0) ||
  // Supabase offline
  (sinal.origem === 'W-2' && sinal.tipo === 'health_check' && sinal.dados.status === 'DOWN')
) {
  categoria = 'DELIBERAR';
  grau = 'A';
  motivo = 'Acao requer veredito do Diretor antes de executar';
}

// --- DELIBERAR-B: Hermes age + confirma com Eduardo ---
else if (
  // Churn atencao (>1x threshold, <2x)
  (sinal.origem === 'W-5' && sinal.tipo === 'churn_atencao') ||
  // Session close com fricao detectada
  (sinal.origem === 'W-4' && sinal.tipo === 'session_close' && sinal.dados.friccoes && sinal.dados.friccoes.length > 0)
) {
  categoria = 'DELIBERAR';
  grau = 'B';
  motivo = 'Hermes age com protocolo padrao + envia confirmacao ao Diretor';
}

// --- DELIBERAR-C: Hermes age autonomamente + loga ---
else if (
  // Session close rotineiro
  (sinal.origem === 'W-4' && sinal.tipo === 'session_close') ||
  // Check-in com dados novos (atualiza WIP_BOARD)
  (sinal.origem === 'W-1' && sinal.tipo === 'check_in')
) {
  categoria = 'DELIBERAR';
  grau = 'C';
  motivo = 'Protocolo pre-aprovado -- Hermes executa + loga em silenced_signals_log';
}

// --- INFORMAR: notificar Eduardo, nenhuma acao automatica ---
else {
  categoria = 'INFORMAR';
  motivo = 'Sinal nao mapeado -- encaminhar ao Diretor para classificacao manual';
}

// Shadow mode: classificar mas NAO silenciar (7 dias de observacao)
const shadowMode = true;
if (shadowMode && silenciar) {
  silenciar = false;  // Shadow: nao silencia ainda
}

// Log do classificador (sempre)
const resultado = {
  shadow_mode: shadowMode,
  sinal_original: sinal,
  classificacao: {
    categoria,
    grau,
    motivo,
    silenciar,
    classificado_em: new Date().toISOString()
  }
};

return [{ json: resultado }];

// Log para silenced_signals_log (Supabase) -- Shadow Mode
// Em producao: sinais AUTO-RESOLVE nao chegam ao Diretor
const dados = $input.first().json;

return [{
  json: {
    acao: 'LOG_SILENCIADO',
    shadow_mode: true,
    nota: 'Em shadow mode: sinal classificado como AUTO-RESOLVE mas NAO silenciado (7 dias observacao)',
    dados: dados,
    timestamp: new Date().toISOString()
  }
}];

// Encaminhar sinal classificado para workflow de destino
// INFORMAR -> Telegram direto
// DELIBERAR-A -> Telegram com urgencia + bloquear Hermes
// DELIBERAR-B -> Hermes age + Telegram confirmacao
// DELIBERAR-C -> Hermes age silencioso + log

const dados = $input.first().json;
const cat   = dados.classificacao.categoria;
const grau  = dados.classificacao.grau;

let destino = 'TELEGRAM_INFORMAR';
let urgente = false;

if (cat === 'DELIBERAR' && grau === 'A') {
  destino = 'TELEGRAM_DELIBERAR_A';
  urgente = true;
} else if (cat === 'DELIBERAR' && grau === 'B') {
  destino = 'HERMES_B';
} else if (cat === 'DELIBERAR' && grau === 'C') {
  destino = 'HERMES_C';
}

return [{
  json: {
    ...dados,
    roteamento: { destino, urgente }
  }
}];
